import { ProductionRecord } from '../types';
import { INITIAL_DATA_SEED } from '../constants';

const STORAGE_KEY = 'pigmea_production_data_v1';

export const getRecords = (): ProductionRecord[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    // Initialize with seed data for demo purposes
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_DATA_SEED));
    return INITIAL_DATA_SEED as ProductionRecord[];
  }
  return JSON.parse(data);
};

export const saveRecord = (record: ProductionRecord): ProductionRecord[] => {
  const current = getRecords();
  const updated = [record, ...current];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  return updated;
};

export const exportToCSV = (records: ProductionRecord[]) => {
  const headers = ['ID', 'Fecha', 'Turno', 'Jefe', 'Máquina', 'Metros', 'Cambios', 'Comentarios'];

  const rows = records.map(r => [
    r.id,
    r.date,
    r.shift,
    r.boss,
    r.machine,
    r.meters,
    r.changesCount,
    `"${r.changesComment}"` // Quote comments to handle internal commas
  ]);

  const csvContent = [
    headers.join(','),
    ...rows.map(row => row.join(','))
  ].join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `pigmea_reporte_${new Date().toISOString().slice(0, 10)}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import { GoogleGenAI } from "@google/genai";
import { ProductionRecord } from "../types";

// Initialize Gemini Client
// Note: In a real production environment, ensure API keys are not exposed to the client directly if possible,
// or use a proxy. For this demo, we rely on the injected process.env.API_KEY.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeShiftData = async (records: ProductionRecord[]): Promise<string> => {
  try {
    // Limit to last 20 records to avoid token limits in this demo
    const recentRecords = records.slice(0, 20);

    const dataSummary = recentRecords.map(r => 
      `- ${r.date} (${r.shift}): ${r.machine} produjo ${r.meters}m con ${r.changesCount} cambios ("${r.changesComment}")`
    ).join('\n');

    const prompt = `
      Actúa como un analista experto en producción industrial para la empresa "Pigmea".
      Analiza los siguientes registros de producción recientes:

      ${dataSummary}

      Proporciona un resumen ejecutivo breve (máximo 150 palabras) en español.
      1. Identifica la máquina con mejor rendimiento.
      2. Detecta patrones negativos en los comentarios de cambios (ej. muchas roturas).
      3. Sugiere una acción de mejora rápida.
      Usa un tono profesional y directivo.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "No se pudo generar el análisis.";
  } catch (error) {
    console.error("Error calling Gemini API:", error);
    return "Error al conectar con el servicio de análisis inteligente. Verifique su conexión o clave API.";
  }
};

import React, { useState } from 'react';
import { Plus, Save, Calendar, CheckCircle } from 'lucide-react';
import { MachineType, ShiftType, BossType, ProductionRecord } from '../types';
import { MACHINES, SHIFTS, BOSSES, COMMON_COMMENTS } from '../constants';
import { saveRecord } from '../services/storageService';

interface ShiftFormProps {
  onRecordSaved: () => void;
}

const ShiftForm: React.FC<ShiftFormProps> = ({ onRecordSaved }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: ShiftType.MORNING,
    boss: BossType.MARTIN,
    machine: MachineType.WH1,
    meters: '',
    changesCount: 0,
    changesComment: ''
  });
  const [successMsg, setSuccessMsg] = useState('');

  const handleSetToday = () => {
    setFormData(prev => ({ ...prev, date: new Date().toISOString().split('T')[0] }));
  };

  const handleMetersChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Remove non-numeric characters to store raw value
    const rawValue = e.target.value.replace(/\D/g, '');
    setFormData(prev => ({ ...prev, meters: rawValue }));
  };

  const formatMeters = (value: string) => {
    if (!value) return '';
    return parseInt(value).toLocaleString('es-ES');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.meters) return;

    const newRecord: ProductionRecord = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      date: formData.date,
      shift: formData.shift,
      boss: formData.boss,
      machine: formData.machine,
      meters: parseInt(formData.meters),
      changesCount: formData.changesCount,
      changesComment: formData.changesComment
    };

    saveRecord(newRecord);
    setSuccessMsg('Registro guardado correctamente');
    onRecordSaved();

    // Reset critical production fields but keep context (date/shift/boss)
    setFormData(prev => ({
      ...prev,
      meters: '',
      changesCount: 0,
      changesComment: ''
    }));

    setTimeout(() => setSuccessMsg(''), 3000);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-blue-600 px-6 py-4 flex items-center justify-between">
        <h2 className="text-white font-bold text-lg flex items-center gap-2">
          <Plus className="w-5 h-5" /> Nuevo Registro
        </h2>
        {successMsg && (
          <span className="bg-green-500 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 animate-pulse">
            <CheckCircle className="w-3 h-3" /> {successMsg}
          </span>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">

        {/* Section 1: Context (Who & When) */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pb-6 border-b border-slate-100">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Fecha</label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <input
                  type="date"
                  required
                  value={formData.date}
                  onChange={e => setFormData({ ...formData, date: e.target.value })}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                />
              </div>
              <button
                type="button"
                onClick={handleSetToday}
                className="px-4 py-2 bg-slate-200 text-slate-700 font-medium rounded-lg hover:bg-slate-300 transition-colors text-sm"
              >
                Hoy
              </button>
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Jefe de Turno</label>
            <select
              value={formData.boss}
              onChange={e => setFormData({ ...formData, boss: e.target.value as BossType })}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
            >
              {BOSSES.map(boss => (
                <option key={boss} value={boss}>{boss}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Turno</label>
            <select
              value={formData.shift}
              onChange={e => setFormData({ ...formData, shift: e.target.value as ShiftType })}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
            >
              {SHIFTS.map(shift => (
                <option key={shift} value={shift}>{shift}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Section 2: Production Data */}
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Máquina</label>
            <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-7 gap-2">
              {MACHINES.map(machine => (
                <button
                  key={machine}
                  type="button"
                  onClick={() => setFormData({ ...formData, machine: machine })}
                  className={`px-2 py-3 rounded-lg text-sm font-bold transition-all border ${
                    formData.machine === machine
                      ? 'bg-blue-600 text-white border-blue-700 shadow-md transform scale-105'
                      : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'
                  }`}
                >
                  {machine}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">
                Metros Producidos
              </label>
              <div className="relative">
                <input
                  type="text"
                  inputMode="numeric"
                  required
                  placeholder="0"
                  value={formatMeters(formData.meters)}
                  onChange={handleMetersChange}
                  className="w-full px-4 py-3 text-xl font-mono text-right bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                />
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-medium">
                  MTS
                </span>
              </div>
            </div>

            <div className="grid grid-cols-[1fr_2fr] gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Cambios</label>
                <input
                  type="number"
                  min="0"
                  value={formData.changesCount}
                  onChange={e => setFormData({ ...formData, changesCount: parseInt(e.target.value) || 0 })}
                  className="w-full px-4 py-3 text-center bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Comentario</label>
                <input
                  list="common-comments"
                  type="text"
                  placeholder="Motivo..."
                  value={formData.changesComment}
                  onChange={e => setFormData({ ...formData, changesComment: e.target.value })}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
                <datalist id="common-comments">
                  {COMMON_COMMENTS.map((c, i) => (
                    <option key={i} value={c} />
                  ))}
                </datalist>
              </div>
            </div>
          </div>
        </div>

        <div className="pt-4">
          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 px-6 rounded-xl shadow-lg shadow-blue-200 transition-all flex items-center justify-center gap-3 active:scale-95 touch-target"
          >
            <Save className="w-6 h-6" />
            GUARDAR REGISTRO
          </button>
        </div>
      </form>
    </div>
  );
};

export default ShiftForm;

import React, { useMemo, useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  Cell, PieChart, Pie, Legend 
} from 'recharts';
import { FileText, Download, TrendingUp, Activity, Sparkles, Loader } from 'lucide-react';
import { ProductionRecord } from '../types';
import { exportToCSV } from '../services/storageService';
import { analyzeShiftData } from '../services/geminiService';

interface DashboardProps {
  records: ProductionRecord[];
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1'];

const Dashboard: React.FC<DashboardProps> = ({ records }) => {
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // 1. Calculate Summary Metrics
  const summary = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const yesterday = new Date(Date.now() - 86400000).toISOString().split('T')[0];

    const todayRecords = records.filter(r => r.date === today);
    const yesterdayRecords = records.filter(r => r.date === yesterday);

    const totalMetersToday = todayRecords.reduce((acc, r) => acc + r.meters, 0);
    const totalMetersYesterday = yesterdayRecords.reduce((acc, r) => acc + r.meters, 0);

    const totalChangesToday = todayRecords.reduce((acc, r) => acc + r.changesCount, 0);
    const changesAvg = todayRecords.length ? (totalChangesToday / todayRecords.length).toFixed(1) : '0';

    // Simple efficiency calc: (Meters / (Changes * penalty + 1)) normalized (mock formula)
    const efficiency = todayRecords.length ? 
      Math.min(100, Math.round((totalMetersToday / (todayRecords.length * 5000)) * 100)) : 0;

    return {
      todayMeters: totalMetersToday,
      growth: yesterdayRecords.length ? ((totalMetersToday - totalMetersYesterday) / totalMetersYesterday) * 100 : 0,
      avgChanges: changesAvg,
      efficiency
    };
  }, [records]);

  // 2. Prepare Chart Data (Meters per Machine)
  const machineData = useMemo(() => {
    const grouped: Record<string, number> = {};
    records.slice(0, 50).forEach(r => {
      grouped[r.machine] = (grouped[r.machine] || 0) + r.meters;
    });
    return Object.entries(grouped).map(([name, value]) => ({ name, value }));
  }, [records]);

  // 3. Prepare Chart Data (Distribution by Shift)
  const shiftData = useMemo(() => {
    const grouped: Record<string, number> = {};
    records.forEach(r => {
      grouped[r.shift] = (grouped[r.shift] || 0) + r.meters;
    });
    return Object.entries(grouped).map(([name, value]) => ({ name, value }));
  }, [records]);

  const handleAIAnalysis = async () => {
    if (records.length === 0) return;
    setIsAnalyzing(true);
    const result = await analyzeShiftData(records);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const handleDownloadReport = () => {
    exportToCSV(records);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Dashboard de Producción</h2>
        <div className="flex gap-2 w-full md:w-auto">
          <button 
            onClick={handleDownloadReport}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg transition-colors text-sm font-medium"
          >
            <Download className="w-4 h-4" /> Exportar CSV
          </button>
          <button 
            onClick={() => window.print()}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-white border border-slate-300 text-slate-700 px-4 py-2 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
          >
            <FileText className="w-4 h-4" /> PDF Report
          </button>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-2">
            <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Producción Hoy</p>
            <TrendingUp className={`w-5 h-5 ${summary.growth >= 0 ? 'text-green-500' : 'text-red-500'}`} />
          </div>
          <h3 className="text-3xl font-bold text-slate-900">{summary.todayMeters.toLocaleString()} m</h3>
          <p className={`text-xs mt-2 font-medium ${summary.growth >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            {summary.growth >= 0 ? '+' : ''}{summary.growth.toFixed(1)}% vs ayer
          </p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-2">
            <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Eficiencia Turno</p>
            <Activity className="w-5 h-5 text-blue-500" />
          </div>
          <h3 className="text-3xl font-bold text-slate-900">{summary.efficiency}%</h3>
          <div className="w-full bg-slate-100 rounded-full h-2 mt-3">
            <div 
              className="bg-blue-500 h-2 rounded-full transition-all duration-1000" 
              style={{ width: `${summary.efficiency}%` }}
            ></div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-2">
            <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Promedio Cambios</p>
            <Activity className="w-5 h-5 text-orange-500" />
          </div>
          <h3 className="text-3xl font-bold text-slate-900">{summary.avgChanges}</h3>
          <p className="text-xs text-slate-400 mt-2 font-medium">Por máquina / día</p>
        </div>
      </div>

      {/* AI Analysis Section */}
      <div className="bg-gradient-to-r from-indigo-50 to-blue-50 border border-indigo-100 rounded-xl p-6">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-lg font-bold text-indigo-900 flex items-center gap-2">
            <Sparkles className="w-5 h-5 text-indigo-600" /> Pigmea AI Insight
          </h3>
          <button 
            onClick={handleAIAnalysis}
            disabled={isAnalyzing}
            className="text-xs bg-indigo-600 text-white px-3 py-1.5 rounded-md hover:bg-indigo-700 disabled:opacity-50 transition-colors"
          >
            {isAnalyzing ? 'Analizando...' : 'Generar Análisis'}
          </button>
        </div>
        {isAnalyzing ? (
           <div className="flex items-center gap-2 text-indigo-600 text-sm animate-pulse">
             <Loader className="w-4 h-4 animate-spin" /> Procesando datos de producción...
           </div>
        ) : aiAnalysis ? (
          <div className="prose prose-sm text-indigo-800 max-w-none whitespace-pre-line">
            {aiAnalysis}
          </div>
        ) : (
          <p className="text-sm text-indigo-400 italic">
            Haga clic para obtener un resumen inteligente de la eficiencia y problemas detectados en los registros recientes.
          </p>
        )}
      </div>

      {/* Charts Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h4 className="text-sm font-bold text-slate-700 mb-6 uppercase">Producción por Máquina (Total)</h4>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={machineData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} tickFormatter={(val) => `${val/1000}k`} />
                <Tooltip 
                  cursor={{fill: '#f1f5f9'}}
                  contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                  {machineData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h4 className="text-sm font-bold text-slate-700 mb-6 uppercase">Distribución por Turno</h4>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={shiftData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                >
                  {shiftData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, PlusCircle, List, Settings } from 'lucide-react';
import ShiftForm from './components/ShiftForm';
import Dashboard from './components/Dashboard';
import { getRecords } from './services/storageService';
import { ProductionRecord } from './types';

// Simple Router State to avoid heavy dependencies like react-router
type View = 'dashboard' | 'entry' | 'list';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('entry');
  const [records, setRecords] = useState<ProductionRecord[]>([]);

  const loadData = () => {
    const data = getRecords();
    setRecords(data);
  };

  useEffect(() => {
    loadData();
