import { ProductionRecord } from '../types';
import { COMMON_COMMENTS } from '../constants';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import 'jspdf-autotable';

const STORAGE_KEY = 'pigmea_production_data_v1';
const CUSTOM_COMMENTS_KEY = 'pigmea_custom_comments_v1';
const SYNC_CHANNEL = new BroadcastChannel('pigmea_realtime_sync');
const LOCAL_EVENT_NAME = 'pigmea_local_update';

// --- DATA MANAGEMENT ---

const getRecordsInternal = (): ProductionRecord[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

export const getRecords = (): ProductionRecord[] => {
  return getRecordsInternal();
};

export const getAvailableComments = (): string[] => {
  const customData = localStorage.getItem(CUSTOM_COMMENTS_KEY);
  const customComments = customData ? JSON.parse(customData) : [];
  // Merge defaults with custom, remove duplicates, sort alphabetically
  return Array.from(new Set([...COMMON_COMMENTS, ...customComments])).sort();
};

const notifyUpdates = () => {
  // Notify other tabs
  SYNC_CHANNEL.postMessage({ type: 'UPDATE' });
  // Notify current tab components immediately
  window.dispatchEvent(new Event(LOCAL_EVENT_NAME));
};

export const saveRecord = (record: ProductionRecord): ProductionRecord[] => {
  const current = getRecordsInternal();
  const updated = [record, ...current];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));

  // Logic to save new custom comment if it's not in the default list
  if (record.changesComment && !COMMON_COMMENTS.includes(record.changesComment)) {
    const customData = localStorage.getItem(CUSTOM_COMMENTS_KEY);
    const customComments: string[] = customData ? JSON.parse(customData) : [];

    if (!customComments.includes(record.changesComment)) {
      customComments.push(record.changesComment);
      localStorage.setItem(CUSTOM_COMMENTS_KEY, JSON.stringify(customComments));
    }
  }

  notifyUpdates();
  return updated;
};

export const deleteRecord = (id: string): void => {
  const current = getRecordsInternal();
  const updated = current.filter(r => r.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  notifyUpdates();
};

export const deleteCustomComment = (commentToDelete: string): string[] => {
  const customData = localStorage.getItem(CUSTOM_COMMENTS_KEY);
  if (!customData) return getAvailableComments();

  let customComments: string[] = JSON.parse(customData);
  customComments = customComments.filter(c => c !== commentToDelete);

  localStorage.setItem(CUSTOM_COMMENTS_KEY, JSON.stringify(customComments));
  return getAvailableComments();
};

export const clearAllRecords = (): void => {
  localStorage.removeItem(STORAGE_KEY);
  // We do NOT clear CUSTOM_COMMENTS_KEY so autocomplete keeps getting smarter
  notifyUpdates();
};

// Real-time Subscription Mechanism
export const subscribeToRecords = (callback: (records: ProductionRecord[]) => void) => {
  // Initial load
  callback(getRecordsInternal());

  const handleMessage = (event: MessageEvent) => {
    if (event.data.type === 'UPDATE') {
      callback(getRecordsInternal());
    }
  };

  const handleStorage = (event: StorageEvent) => {
    if (event.key === STORAGE_KEY) {
      callback(getRecordsInternal());
    }
  };

  const handleLocalUpdate = () => {
    callback(getRecordsInternal());
  };

  SYNC_CHANNEL.addEventListener('message', handleMessage);
  window.addEventListener('storage', handleStorage);
  window.addEventListener(LOCAL_EVENT_NAME, handleLocalUpdate);

  return () => {
    SYNC_CHANNEL.removeEventListener('message', handleMessage);
    window.removeEventListener('storage', handleStorage);
    window.removeEventListener(LOCAL_EVENT_NAME, handleLocalUpdate);
  };
};

// --- EXPORT FUNCTIONS ---

export const exportToExcel = (records: ProductionRecord[]) => {
  // Format data for Excel
  const data = records.map(r => ({
    'Fecha': r.date,
    'Turno': r.shift,
    'Jefe de Turno': r.boss,
    'Máquina': r.machine,
    'Metros': r.meters,
    'Cambios': r.changesCount,
    'Comentarios/Incidencias': r.changesComment
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Producción");

  // Auto-width columns (approximate)
  const wscols = [
    {wch: 12}, {wch: 10}, {wch: 15}, {wch: 10}, {wch: 12}, {wch: 10}, {wch: 30}
  ];
  worksheet['!cols'] = wscols;

  XLSX.writeFile(workbook, `Reporte_Produccion_${new Date().toISOString().slice(0, 10)}.xlsx`);
};

export const exportToPDF = (records: ProductionRecord[]) => {
  const doc = new jsPDF();

  // Header
  doc.setFontSize(18);
  doc.setTextColor(40);
  doc.text("Reporte de Producción - Registro Jefe de Turnos", 14, 22);

  doc.setFontSize(11);
  doc.setTextColor(100);
  doc.text(`Fecha de generación: ${new Date().toLocaleDateString()}`, 14, 30);

  // Table Data
  const tableColumn = ["Fecha", "Turno", "Jefe", "Máquina", "Metros", "Cambios", "Comentarios"];
  const tableRows = records.map(r => [
    r.date,
    r.shift,
    r.boss,
    r.machine,
    r.meters.toLocaleString(),
    r.changesCount,
    r.changesComment
  ]);

  // Generate Table
  (doc as any).autoTable({
    head: [tableColumn],
    body: tableRows,
    startY: 40,
    theme: 'grid',
    styles: { fontSize: 9, cellPadding: 3 },
    headStyles: { fillColor: [41, 128, 185], textColor: 255 }, // Blue header
    alternateRowStyles: { fillColor: [245, 245, 245] }
  });

  doc.save(`Reporte_Produccion_${new Date().toISOString().slice(0, 10)}.pdf`);
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Save, Calendar, CheckCircle, X, ChevronDown, MessageSquare, Trash2 } from 'lucide-react';
import { MachineType, ShiftType, BossType, ProductionRecord } from '../types';
import { MACHINES, SHIFTS, BOSSES } from '../constants';
import { saveRecord, getAvailableComments, deleteCustomComment } from '../services/storageService';

interface ShiftFormProps {
  onRecordSaved: () => void;
}

const ShiftForm: React.FC<ShiftFormProps> = ({ onRecordSaved }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: ShiftType.MORNING,
    boss: BossType.MARTIN,
    machine: MachineType.WH1,
  });

  // Handle inputs as strings to prevent "0" prefix issues on mobile
  const [metersInput, setMetersInput] = useState('');
  const [changesInput, setChangesInput] = useState('');

  // Custom Comment Field State
  const [commentInput, setCommentInput] = useState('');
  const [availableComments, setAvailableComments] = useState<string[]>([]);
  const [filteredComments, setFilteredComments] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const [successMsg, setSuccessMsg] = useState('');

  // Load comments initially and ensure they are up to date
  const refreshComments = () => {
    const comments = getAvailableComments();
    setAvailableComments(comments);
    return comments;
  };

  useEffect(() => {
    refreshComments();
  }, []);

  // Filter logic
  useEffect(() => {
    if (!commentInput) {
      setFilteredComments(availableComments);
    } else {
      const lowerInput = commentInput.toLowerCase();
      setFilteredComments(availableComments.filter(c => 
        c.toLowerCase().includes(lowerInput)
      ));
    }
  }, [commentInput, availableComments]);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleMetersChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setMetersInput(rawValue);
  };

  const handleChangesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setChangesInput(rawValue);
  };

  const formatMeters = (value: string) => {
    if (!value) return '';
    return parseInt(value).toLocaleString('es-ES');
  };

  const clearComment = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent triggering dropdown toggle if overlapping
    setCommentInput('');
    setFilteredComments(availableComments);
    // Keep focus on input ideally, or just clear
  };

  const handleInputFocus = () => {
    refreshComments(); // Sync latest comments from storage on focus
    setShowSuggestions(true);
  };

  const selectComment = (comment: string) => {
    setCommentInput(comment);
    setShowSuggestions(false);
  };

  const handleDeleteComment = (e: React.MouseEvent, comment: string) => {
    e.stopPropagation();
    if (confirm(`¿Borrar "${comment}" de la lista de autocompletado?`)) {
      deleteCustomComment(comment);
      refreshComments();
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!metersInput) return;

    const newRecord: ProductionRecord = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      date: formData.date,
      shift: formData.shift,
      boss: formData.boss,
      machine: formData.machine,
      meters: parseInt(metersInput),
      changesCount: changesInput === '' ? 0 : parseInt(changesInput),
      changesComment: commentInput
    };

    saveRecord(newRecord);
    setSuccessMsg('Registro guardado');
    onRecordSaved();

    // Refresh available comments in case a new one was added
    refreshComments();

    // Reset production fields only
    setMetersInput('');
    setChangesInput('');
    setCommentInput('');

    setTimeout(() => setSuccessMsg(''), 3000);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-20 md:mb-0">
      <div className="bg-blue-600 px-6 py-4 flex items-center justify-between">
        <h2 className="text-white font-bold text-lg flex items-center gap-2">
          <Plus className="w-5 h-5" /> Nuevo Registro
        </h2>
        {successMsg && (
          <span className="bg-green-500 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 animate-pulse shadow-sm">
            <CheckCircle className="w-3 h-3" /> {successMsg}
          </span>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">

        {/* Context Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pb-6 border-b border-slate-100">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2 flex items-center gap-2">
              <Calendar className="w-4 h-4 text-slate-400" /> Fecha de Turno
            </label>
            <input
              type="date"
              required
              value={formData.date}
              onChange={e => setFormData({ ...formData, date: e.target.value })}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all font-medium text-slate-700"
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Jefe de Turno</label>
            <div className="relative">
              <select
                value={formData.boss}
                onChange={e => setFormData({ ...formData, boss: e.target.value as BossType })}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none font-medium"
              >
                {BOSSES.map(boss => (
                  <option key={boss} value={boss}>{boss}</option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none">
                <ChevronDown className="w-4 h-4 text-slate-500" />
              </div>
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Turno</label>
            <div className="relative">
              <select
                value={formData.shift}
                onChange={e => setFormData({ ...formData, shift: e.target.value as ShiftType })}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none font-medium"
              >
                {SHIFTS.map(shift => (
                  <option key={shift} value={shift}>{shift}</option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none">
                <ChevronDown className="w-4 h-4 text-slate-500" />
              </div>
            </div>
          </div>
        </div>

        {/* Production Data */}
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Seleccionar Máquina</label>
