const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);

import { ProductionRecord } from '../types';
import { COMMON_COMMENTS } from '../constants';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import 'jspdf-autotable';
import { db } from './firebase';
import { 
  collection, 
  doc, 
  setDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs,
  updateDoc,
  arrayUnion,
  arrayRemove,
  getDoc
} from 'firebase/firestore';

const RECORDS_COLLECTION = 'production_records';
const SETTINGS_COLLECTION = 'app_settings';
const COMMENTS_DOC_ID = 'custom_comments';

// Local cache to serve synchronous get requests (for exports)
let localRecordsCache: ProductionRecord[] = [];
let localCommentsCache: string[] = [...COMMON_COMMENTS];

// --- DATA MANAGEMENT ---

// This function now returns the cache, which is kept up-to-date by the subscription
export const getRecords = (): ProductionRecord[] => {
  return localRecordsCache;
};

// Initialize comments listener internally when the app starts
const initCommentsListener = () => {
  const docRef = doc(db, SETTINGS_COLLECTION, COMMENTS_DOC_ID);
  onSnapshot(docRef, (docSnap) => {
    if (docSnap.exists()) {
      const data = docSnap.data();
      const customComments = data.list || [];
      localCommentsCache = Array.from(new Set([...COMMON_COMMENTS, ...customComments])).sort();
    } else {
      // Create doc if it doesn't exist
      setDoc(docRef, { list: [] });
    }
  });
};
// Start listening for comments immediately
initCommentsListener();

export const getAvailableComments = (): string[] => {
  return localCommentsCache;
};

export const saveRecord = async (record: ProductionRecord): Promise<void> => {
  try {
    // 1. Save the record to Firestore
    await setDoc(doc(db, RECORDS_COLLECTION, record.id), record);

    // 2. Handle Custom Comments
    if (record.changesComment && !COMMON_COMMENTS.includes(record.changesComment)) {
      const docRef = doc(db, SETTINGS_COLLECTION, COMMENTS_DOC_ID);
      // Use arrayUnion to atomically add without duplicates
      await updateDoc(docRef, {
        list: arrayUnion(record.changesComment)
      }).catch(async (err) => {
        // If document doesn't exist, create it (fallback)
        if (err.code === 'not-found') {
          await setDoc(docRef, { list: [record.changesComment] });
        }
      });
    }
  } catch (e) {
    console.error("Error saving record:", e);
    alert("Error al guardar en la nube. Verifique su conexión.");
  }
};

export const deleteRecord = async (id: string): Promise<void> => {
  try {
    await deleteDoc(doc(db, RECORDS_COLLECTION, id));
  } catch (e) {
    console.error("Error deleting record:", e);
    alert("Error al borrar. Verifique su conexión.");
  }
};

export const deleteCustomComment = async (commentToDelete: string): Promise<string[]> => {
  try {
    const docRef = doc(db, SETTINGS_COLLECTION, COMMENTS_DOC_ID);
    await updateDoc(docRef, {
      list: arrayRemove(commentToDelete)
    });
    // The snapshot listener will update the cache automatically
    return localCommentsCache;
  } catch (e) {
    console.error("Error deleting comment:", e);
    return localCommentsCache;
  }
};

export const clearAllRecords = async (): Promise<void> => {
  // Firestore doesn't have a "delete collection" method for clients for safety.
  // We must retrieve and delete individually or in batches.
  const q = query(collection(db, RECORDS_COLLECTION));
  const snapshot = await getDocs(q);

  const deletePromises = snapshot.docs.map(d => deleteDoc(d.ref));
  await Promise.all(deletePromises);
};

// Real-time Subscription Mechanism
export const subscribeToRecords = (callback: (records: ProductionRecord[]) => void) => {
  const q = query(collection(db, RECORDS_COLLECTION), orderBy('timestamp', 'desc'));

  const unsubscribe = onSnapshot(q, (snapshot) => {
    const records: ProductionRecord[] = [];
    snapshot.forEach((doc) => {
      records.push(doc.data() as ProductionRecord);
    });

    // Update local cache
    localRecordsCache = records;

    // Notify UI
    callback(records);
  }, (error) => {
    console.error("Error getting realtime updates:", error);
  });

  return unsubscribe;
};

// --- EXPORT FUNCTIONS (Unchanged logic, uses local cache) ---

export const exportToExcel = (records: ProductionRecord[]) => {
  const data = records.map(r => ({
    'Fecha': r.date,
    'Turno': r.shift,
    'Jefe de Turno': r.boss,
    'Máquina': r.machine,
    'Metros': r.meters,
    'Cambios': r.changesCount,
    'Comentarios/Incidencias': r.changesComment
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Producción");

  const wscols = [
    {wch: 12}, {wch: 10}, {wch: 15}, {wch: 10}, {wch: 12}, {wch: 10}, {wch: 30}
  ];
  worksheet['!cols'] = wscols;

  XLSX.writeFile(workbook, `Reporte_Produccion_${new Date().toISOString().slice(0, 10)}.xlsx`);
};

export const exportToPDF = (records: ProductionRecord[]) => {
  const doc = new jsPDF();

  doc.setFontSize(18);
  doc.setTextColor(40);
  doc.text("Reporte de Producción - Registro Jefe de Turnos", 14, 22);

  doc.setFontSize(11);
  doc.setTextColor(100);
  doc.text(`Fecha de generación: ${new Date().toLocaleDateString()}`, 14, 30);

  const tableColumn = ["Fecha", "Turno", "Jefe", "Máquina", "Metros", "Cambios", "Comentarios"];
  const tableRows = records.map(r => [
    r.date,
    r.shift,
    r.boss,
    r.machine,
    r.meters.toLocaleString(),
    r.changesCount,
    r.changesComment
  ]);

  (doc as any).autoTable({
    head: [tableColumn],
    body: tableRows,
    startY: 40,
    theme: 'grid',
    styles: { fontSize: 9, cellPadding: 3 },
    headStyles: { fillColor: [41, 128, 185], textColor: 255 }, 
    alternateRowStyles: { fillColor: [245, 245, 245] }
  });

  doc.save(`Reporte_Produccion_${new Date().toISOString().slice(0, 10)}.pdf`);
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Save, Calendar, CheckCircle, X, ChevronDown, MessageSquare, Trash2 } from 'lucide-react';
import { MachineType, ShiftType, BossType, ProductionRecord } from '../types';
import { MACHINES, SHIFTS, BOSSES } from '../constants';
import { saveRecord, getAvailableComments, deleteCustomComment } from '../services/storageService';

interface ShiftFormProps {
  onRecordSaved: () => void;
}

const ShiftForm: React.FC<ShiftFormProps> = ({ onRecordSaved }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: ShiftType.MORNING,
    boss: BossType.MARTIN,
    machine: MachineType.WH1,
  });

  // Handle inputs as strings to prevent "0" prefix issues on mobile
  const [metersInput, setMetersInput] = useState('');
  const [changesInput, setChangesInput] = useState('');

  // Custom Comment Field State
  const [commentInput, setCommentInput] = useState('');
  const [availableComments, setAvailableComments] = useState<string[]>([]);
  const [filteredComments, setFilteredComments] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const [successMsg, setSuccessMsg] = useState('');

  // Load comments initially and ensure they are up to date
  const refreshComments = () => {
    const comments = getAvailableComments();
    setAvailableComments(comments);
    return comments;
  };

  // Poll for comment updates initially to sync with Firestore
  useEffect(() => {
    refreshComments();
    const interval = setInterval(refreshComments, 2000); // Check for cloud updates to comments
    return () => clearInterval(interval);
  }, []);

  // Filter logic
  useEffect(() => {
    if (!commentInput) {
      setFilteredComments(availableComments);
    } else {
      const lowerInput = commentInput.toLowerCase();
      setFilteredComments(availableComments.filter(c => 
        c.toLowerCase().includes(lowerInput)
      ));
    }
  }, [commentInput, availableComments]);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleMetersChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setMetersInput(rawValue);
  };

  const handleChangesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setChangesInput(rawValue);
  };

  const formatMeters = (value: string) => {
    if (!value) return '';
    return parseInt(value).toLocaleString('es-ES');
  };

  const clearComment = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent triggering dropdown toggle if overlapping
    setCommentInput('');
    setFilteredComments(availableComments);
    // Keep focus on input ideally, or just clear
  };

  const handleInputFocus = () => {
    refreshComments(); // Sync latest comments from storage on focus
    setShowSuggestions(true);
  };

  const selectComment = (comment: string) => {
    setCommentInput(comment);
    setShowSuggestions(false);
  };

  const handleDeleteComment = async (e: React.MouseEvent, comment: string) => {
    e.stopPropagation();
    if (confirm(`¿Borrar "${comment}" de la lista de autocompletado?`)) {
      await deleteCustomComment(comment);
      refreshComments();
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!metersInput) return;

    const newRecord: ProductionRecord = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      date: formData.date,
      shift: formData.shift,
      boss: formData.boss,
      machine: formData.machine,
      meters: parseInt(metersInput),
      changesCount: changesInput === '' ? 0 : parseInt(changesInput),
      changesComment: commentInput
    };

    await saveRecord(newRecord);
    setSuccessMsg('Registro guardado');
    onRecordSaved();

    // Refresh available comments in case a new one was added
    refreshComments();

    // Reset production fields only
    setMetersInput('');
    setChangesInput('');
    setCommentInput('');

    setTimeout(() => setSuccessMsg(''), 3000);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-20 md:mb-0">
      <div className="bg-blue-600 px-6 py-4 flex items-center justify-between">
        <h2 className="text-white font-bold text-lg flex items-center gap-2">
          <Plus className="w-5 h-5" /> Nuevo Registro
        </h2>
        {successMsg && (
          <span className="bg-green-500 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 animate-pulse shadow-sm">
            <CheckCircle className="w-3 h-3" /> {successMsg}
          </span>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">

        {/* Context Grid */}
