import React, { useState, useEffect, useRef } from 'react';
import { Plus, Save, Calendar, CheckCircle, X, ChevronDown, MessageSquare, Trash2, RotateCcw } from 'lucide-react';
import { MachineType, ShiftType, BossType, ProductionRecord } from '../types';
import { MACHINES, SHIFTS, BOSSES } from '../constants';
import { saveRecord, getAvailableComments, deleteCustomComment } from '../services/storageService';

interface ShiftFormProps {
  onRecordSaved: () => void;
  editingRecord?: ProductionRecord | null;
  onCancelEdit?: () => void;
}

const ShiftForm: React.FC<ShiftFormProps> = ({ onRecordSaved, editingRecord, onCancelEdit }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: ShiftType.MORNING,
    boss: BossType.MARTIN,
    machine: MachineType.WH1,
  });

  // Handle inputs as strings to prevent "0" prefix issues on mobile
  const [metersInput, setMetersInput] = useState('');
  const [changesInput, setChangesInput] = useState('');

  // Custom Comment Field State
  const [commentInput, setCommentInput] = useState('');
  const [availableComments, setAvailableComments] = useState<string[]>([]);
  const [filteredComments, setFilteredComments] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const [successMsg, setSuccessMsg] = useState('');

  // Load editing data when record changes
  useEffect(() => {
    if (editingRecord) {
      setFormData({
        date: editingRecord.date,
        shift: editingRecord.shift,
        boss: editingRecord.boss,
        machine: editingRecord.machine,
      });
      setMetersInput(editingRecord.meters.toString());
      setChangesInput(editingRecord.changesCount.toString());
      setCommentInput(editingRecord.changesComment || '');
      // Scroll to top when editing starts
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      // Reset to defaults if not editing
      setFormData({
        date: new Date().toISOString().split('T')[0],
        shift: ShiftType.MORNING,
        boss: BossType.MARTIN,
        machine: MachineType.WH1,
      });
      setMetersInput('');
      setChangesInput('');
      setCommentInput('');
    }
  }, [editingRecord]);

  // Load comments initially and ensure they are up to date
  const refreshComments = () => {
    const comments = getAvailableComments();
    setAvailableComments(comments);
    return comments;
  };

  // Poll for comment updates initially to sync with Firestore
  useEffect(() => {
    refreshComments();
    const interval = setInterval(refreshComments, 2000); // Check for cloud updates to comments
    return () => clearInterval(interval);
  }, []);

  // Filter logic
  useEffect(() => {
    if (!commentInput) {
      setFilteredComments(availableComments);
    } else {
      const lowerInput = commentInput.toLowerCase();
      setFilteredComments(availableComments.filter(c => 
        c.toLowerCase().includes(lowerInput)
      ));
    }
  }, [commentInput, availableComments]);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleMetersChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setMetersInput(rawValue);
  };

  const handleChangesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setChangesInput(rawValue);
  };

  const formatMeters = (value: string) => {
    if (!value) return '';
    return parseInt(value).toLocaleString('es-ES');
  };

  const clearComment = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent triggering dropdown toggle if overlapping
    setCommentInput('');
    setFilteredComments(availableComments);
    // Keep focus on input ideally, or just clear
  };

  const handleInputFocus = () => {
    refreshComments(); // Sync latest comments from storage on focus
    setShowSuggestions(true);
  };

  const selectComment = (comment: string) => {
    setCommentInput(comment);
    setShowSuggestions(false);
  };

  const handleDeleteComment = async (e: React.MouseEvent, comment: string) => {
    e.stopPropagation();
    if (confirm(`¿Borrar "${comment}" de la lista de autocompletado?`)) {
      await deleteCustomComment(comment);
      refreshComments();
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!metersInput) return;

    // Use existing ID if editing, else generate new
    const id = editingRecord ? editingRecord.id : crypto.randomUUID();
    const timestamp = editingRecord ? editingRecord.timestamp : Date.now();

    const newRecord: ProductionRecord = {
      id,
      timestamp,
      date: formData.date,
      shift: formData.shift,
      boss: formData.boss,
      machine: formData.machine,
      meters: parseInt(metersInput),
      changesCount: changesInput === '' ? 0 : parseInt(changesInput),
      changesComment: commentInput
    };

    await saveRecord(newRecord);
    setSuccessMsg(editingRecord ? 'Registro actualizado' : 'Registro guardado');
    onRecordSaved();

    // Refresh available comments in case a new one was added
    refreshComments();

    if (!editingRecord) {
      // Reset production fields only if not editing (if editing, the parent will unmount/reset us)
      setMetersInput('');
      setChangesInput('');
      setCommentInput('');
    }

    setTimeout(() => setSuccessMsg(''), 3000);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-20 md:mb-0">
      <div className={`px-6 py-4 flex items-center justify-between ${editingRecord ? 'bg-orange-600' : 'bg-blue-600'}`}>
        <h2 className="text-white font-bold text-lg flex items-center gap-2">
          {editingRecord ? <RotateCcw className="w-5 h-5" /> : <Plus className="w-5 h-5" />} 
          {editingRecord ? 'Modificar Registro' : 'Nuevo Registro'}
        </h2>
        {successMsg && (
          <span className="bg-green-500 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 animate-pulse shadow-sm">
            <CheckCircle className="w-3 h-3" /> {successMsg}
          </span>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">

        {/* Context Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pb-6 border-b border-slate-100">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2 flex items-center gap-2">
              <Calendar className="w-4 h-4 text-slate-400" /> Fecha de Turno
            </label>
            <input
              type="date"
              required
              value={formData.date}
              onChange={e => setFormData({ ...formData, date: e.target.value })}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all font-medium text-slate-700"
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Jefe de Turno</label>
            <div className="relative">
              <select
                value={formData.boss}
                onChange={e => setFormData({ ...formData, boss: e.target.value as BossType })}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none font-medium"
              >
                {BOSSES.map(boss => (
                  <option key={boss} value={boss}>{boss}</option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none">
                <ChevronDown className="w-4 h-4 text-slate-500" />
              </div>
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Turno</label>
            <div className="relative">
              <select
                value={formData.shift}
                onChange={e => setFormData({ ...formData, shift: e.target.value as ShiftType })}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none font-medium"
              >
                {SHIFTS.map(shift => (
                  <option key={shift} value={shift}>{shift}</option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none">
                <ChevronDown className="w-4 h-4 text-slate-500" />
              </div>
            </div>
          </div>
        </div>

        {/* Production Data */}
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Seleccionar Máquina</label>
            <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-7 gap-2">
              {MACHINES.map(machine => (
                <button
                  key={machine}
                  type="button"
                  onClick={() => setFormData({ ...formData, machine: machine })}
                  className={`px-2 py-4 rounded-xl text-sm font-bold transition-all border shadow-sm ${
                    formData.machine === machine
                      ? 'bg-slate-800 text-white border-slate-900 shadow-md transform scale-105 ring-2 ring-offset-1 ring-slate-800'
                      : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300'
                  }`}
                >
                  {machine}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <label className="block text-sm font-semibold text-slate-700 mb-2">
                Metros Producidos
              </label>
              <div className="relative">
                <input
                  type="text"
                  inputMode="numeric"
                  required
                  placeholder="0"
                  value={formatMeters(metersInput)}
                  onChange={handleMetersChange}
                  className="w-full px-4 py-3 text-2xl font-mono font-bold text-right bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none shadow-inner"
                />
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-xs tracking-wider">
                  MTS
                </span>
              </div>
            </div>

            <div className="grid grid-cols-[1fr_2fr] gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Cambios</label>
                <input
                  type="text"
                  inputMode="numeric"
                  placeholder="0"
                  value={changesInput}
                  onChange={handleChangesChange}
                  className="w-full px-4 py-3 text-center bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-lg"
                />
              </div>

              <div className="relative" ref={dropdownRef}>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Comentario / Incidencia</label>
                <div className="relative w-full">
                  <div className="relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                       <MessageSquare className="w-4 h-4" />
                    </div>
                    <input
                      type="text"
                      placeholder="Seleccionar o escribir..."
                      value={commentInput}
                      onChange={e => {
                        setCommentInput(e.target.value);
                        setShowSuggestions(true);
                      }}
                      onFocus={handleInputFocus}
                      className="w-full pl-10 pr-10 py-3 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                      autoComplete="off"
                    />

                    {/* Actions Right */}
                    <div className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center">
                      {commentInput && (
                        <button
                          type="button"
                          onClick={clearComment}
                          className="p-1.5 text-slate-400 hover:text-red-500 transition-colors bg-slate-100 rounded-full mr-1"
                        >
                          <X className="w-3 h-3" />
                        </button>
                      )}
                      <div className={`pointer-events-none text-slate-400 p-1 transition-transform duration-200 ${showSuggestions ? 'rotate-180' : ''}`}>
                         <ChevronDown className="w-4 h-4" />
                      </div>
                    </div>
                  </div>

                  {/* Custom Mobile-Friendly Dropdown */}
                  {showSuggestions && (
                    <div className="absolute z-50 w-full bottom-full mb-2 bg-white border border-slate-200 rounded-xl shadow-xl max-h-60 overflow-y-auto animate-fade-in origin-bottom">
                      {filteredComments.length > 0 ? (
                        <div className="divide-y divide-slate-50">
                          {filteredComments.map((comment, index) => (
                            <div
                              key={index}
                              onClick={() => selectComment(comment)}
                              className="w-full text-left px-4 py-3.5 hover:bg-blue-50 active:bg-blue-100 text-slate-700 font-medium transition-colors flex items-center justify-between group touch-target cursor-pointer"
                            >
                              <div className="flex items-center gap-3 overflow-hidden">
                                <span className="w-1.5 h-1.5 rounded-full bg-blue-400 shrink-0"></span>
                                <span className="truncate">{comment}</span>
                              </div>
                              <button
                                type="button"
                                onClick={(e) => handleDeleteComment(e, comment)}
                                className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-all opacity-100 md:opacity-0 group-hover:opacity-100"
                                title="Borrar de la lista"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                            </div>
                          ))}
                        </div>
                      ) : (
                        <div className="px-4 py-4 text-center">
                           <p className="text-slate-400 text-sm mb-1">Nueva incidencia</p>
                           <p className="text-blue-600 font-bold text-sm break-words">"{commentInput}"</p>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="pt-2 pb-6 flex gap-3">
          {editingRecord && (
            <button
              type="button"
              onClick={onCancelEdit}
              className="flex-1 bg-slate-200 hover:bg-slate-300 text-slate-700 font-bold py-4 px-6 rounded-xl transition-all flex items-center justify-center gap-3 touch-target"
            >
              CANCELAR
            </button>
          )}

          <button
            type="submit"
            className={`flex-1 ${editingRecord ? 'bg-orange-600 hover:bg-orange-700 shadow-orange-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'} text-white font-bold py-4 px-6 rounded-xl shadow-lg transition-all flex items-center justify-center gap-3 active:scale-[0.98] touch-target text-lg`}
          >
            <Save className="w-6 h-6" />
            {editingRecord ? 'ACTUALIZAR' : 'GUARDAR'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default ShiftForm;

import { ProductionRecord } from '../types';
import { COMMON_COMMENTS } from '../constants';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import 'jspdf-autotable';
import { db } from './firebase';
import { 
  collection, 
  doc, 
  setDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs,
  updateDoc,
  arrayUnion,
  arrayRemove,
  getDoc,
  where,
  writeBatch
} from 'firebase/firestore';

const RECORDS_COLLECTION = 'production_records';
const SETTINGS_COLLECTION = 'app_settings';
const COMMENTS_DOC_ID = 'custom_comments';

// Local cache to serve synchronous get requests (for exports)
let localRecordsCache: ProductionRecord[] = [];
let localCommentsCache: string[] = [...COMMON_COMMENTS];

// --- DATA MANAGEMENT ---

// This function now returns the cache, which is kept up-to-date by the subscription
export const getRecords = (): ProductionRecord[] => {
  return localRecordsCache;
};

// Initialize comments listener internally when the app starts
const initCommentsListener = () => {
  const docRef = doc(db, SETTINGS_COLLECTION, COMMENTS_DOC_ID);
  onSnapshot(docRef, (docSnap) => {
    if (docSnap.exists()) {
      const data = docSnap.data();
      const customComments = data.list || [];
      localCommentsCache = Array.from(new Set([...COMMON_COMMENTS, ...customComments])).sort();
    } else {
      // Create doc if it doesn't exist
      setDoc(docRef, { list: [] }).catch(err => console.log("Init comments unavailable (offline/no-db)"));
    }
  }, (err) => {
     console.warn("Comments listener warning:", err.code);
  });
};
// Start listening for comments immediately
initCommentsListener();

export const getAvailableComments = (): string[] => {
  return localCommentsCache;
};

export const saveRecord = async (record: ProductionRecord): Promise<void> => {
  try {
    // 1. Save the record to Firestore
    await setDoc(doc(db, RECORDS_COLLECTION, record.id), record);

    // 2. Handle Custom Comments
    if (record.changesComment && !COMMON_COMMENTS.includes(record.changesComment)) {
      const docRef = doc(db, SETTINGS_COLLECTION, COMMENTS_DOC_ID);
      // Use arrayUnion to atomically add without duplicates
      await updateDoc(docRef, {
        list: arrayUnion(record.changesComment)
      }).catch(async (err) => {
        // If document doesn't exist, create it (fallback)
        if (err.code === 'not-found') {
          await setDoc(docRef, { list: [record.changesComment] });
        }
      });
    }
  } catch (e: any) {
    console.error("Error saving record:", e);
    if (e.code === 'permission-denied') {
      alert("Error de Permisos: Configure las Reglas de Firestore a 'allow read, write: if true;' en la consola.");
    }
    throw e; // Propagate error so UI can show it if needed
  }
};

export const deleteRecord = async (id: string): Promise<void> => {
  try {
    await deleteDoc(doc(db, RECORDS_COLLECTION, id));
  } catch (e) {
    console.error("Error deleting record:", e);
    alert("Error al borrar. Verifique su conexión.");
  }
};

export const deleteCustomComment = async (commentToDelete: string): Promise<string[]> => {
  try {
    const docRef = doc(db, SETTINGS_COLLECTION, COMMENTS_DOC_ID);
    await updateDoc(docRef, {
      list: arrayRemove(commentToDelete)
    });
    return localCommentsCache;
  } catch (e) {
    console.error("Error deleting comment:", e);
    return localCommentsCache;
  }
};

/**
 * Renames a comment in the settings list AND updates all past records that used it.
 */
export const renameCustomComment = async (oldName: string, newName: string): Promise<void> => {
  if (!oldName || !newName || oldName === newName) return;

  try {
    const batch = writeBatch(db);
    const settingsRef = doc(db, SETTINGS_COLLECTION, COMMENTS_DOC_ID);

    // 1. Update the list in settings (Atomic operations not fully possible with array manipulation in batch mixed with others easily, 
    // so we do updateDoc for the list, then batch for records).

    // Remove old, Add new (Standardizes the list)
    await updateDoc(settingsRef, {
      list: arrayRemove(oldName)
    });
    await updateDoc(settingsRef, {
      list: arrayUnion(newName)
    });

    // 2. Find all records with the old comment
    const q = query(
      collection(db, RECORDS_COLLECTION), 
      where('changesComment', '==', oldName)
    );
    const querySnapshot = await getDocs(q);

    // 3. Queue updates for all matching records
    querySnapshot.forEach((doc) => {
      batch.update(doc.ref, { changesComment: newName });
    });

    // 4. Commit all record updates at once
    await batch.commit();

  } catch (e) {
    console.error("Error renaming comment globally:", e);
    throw new Error("No se pudo renombrar el comentario.");
  }
};

export const clearAllRecords = async (): Promise<void> => {
  // Firestore doesn't have a "delete collection" method for clients for safety.
  // We must retrieve and delete individually or in batches.
  const q = query(collection(db, RECORDS_COLLECTION));
  const snapshot = await getDocs(q);

  const deletePromises = snapshot.docs.map(d => deleteDoc(d.ref));
  await Promise.all(deletePromises);
};

// Real-time Subscription Mechanism
export const subscribeToRecords = (
  callback: (records: ProductionRecord[]) => void,
  onError?: (errorMsg: string) => void
) => {
  const q = query(collection(db, RECORDS_COLLECTION), orderBy('timestamp', 'desc'));

  const unsubscribe = onSnapshot(q, (snapshot) => {
    const records: ProductionRecord[] = [];
    snapshot.forEach((doc) => {
      records.push(doc.data() as ProductionRecord);
    });

    // Update local cache
    localRecordsCache = records;

    // Notify UI
    callback(records);

    // Clear any previous errors on success
    if (onError) onError('');

  }, (error) => {
    console.error("Firestore Error:", error);
    let msg = "Error de conexión con la base de datos.";

    // Handle specific codes
    if (error.code === 'permission-denied') {
      msg = "ACCESO DENEGADO: Vaya a Firebase Console > Firestore > Reglas y cambie a 'allow read, write: if true;'";
    } else if (error.code === 'not-found' || error.message.includes('database (default) does not exist')) {
      msg = "La base de datos no existe. Requiere configuración en Google Cloud.";
    } else if (error.code === 'unavailable') {
      msg = "Servicio no disponible (Offline).";
    }

    if (onError) onError(msg);
  });

  return unsubscribe;
};

