                         <button onClick={() => setEditingCommentOldName(null)} className="p-1.5 bg-slate-300 text-slate-600 rounded hover:bg-slate-400">
                           <X className="w-4 h-4" />
                         </button>
                       </div>
                     ) : (
                       <>
                         <span className="text-sm font-medium text-slate-700 break-words flex-1">{comment}</span>
                         <div className="flex items-center gap-1 shrink-0">
                           <button 
                             onClick={() => startEditingComment(comment)}
                             className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded transition-colors"
                             title="Renombrar y unificar"
                           >
                             <Edit2 className="w-4 h-4" />
                           </button>
                           {!isCommon && (
                             <button 
                               onClick={() => handleDeleteComment(comment)}
                               className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded transition-colors"
                               title="Borrar de la lista (Mantiene registros)"
                             >
                               <Trash2 className="w-4 h-4" />
                             </button>
                           )}
                         </div>
                       </>
                     )}
                   </div>
                 );
              })}
              {availableComments.length === 0 && (
                <div className="text-center p-8 text-slate-400 text-sm">No hay comentarios personalizados.</div>
              )}
            </div>

            <div className="p-4 bg-slate-50 border-t border-slate-200 text-center">
              <button 
                onClick={() => setShowManageModal(false)}
                className="text-sm font-bold text-slate-600 hover:text-slate-900"
              >
                Cerrar
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default ShiftForm;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Save, Calendar, CheckCircle, X, ChevronDown, MessageSquare, Trash2, RotateCcw, Settings, Edit2 } from 'lucide-react';
import { MachineType, ShiftType, BossType, ProductionRecord } from '../types';
import { MACHINES, SHIFTS, BOSSES, COMMON_COMMENTS } from '../constants';
import { saveRecord, getAvailableComments, deleteCustomComment, renameCustomComment } from '../services/storageService';

interface ShiftFormProps {
  onRecordSaved: () => void;
  editingRecord?: ProductionRecord | null;
  onCancelEdit?: () => void;
}

const ShiftForm: React.FC<ShiftFormProps> = ({ onRecordSaved, editingRecord, onCancelEdit }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: ShiftType.MORNING,
    boss: BossType.MARTIN,
    machine: MachineType.WH1,
  });

  // Handle inputs as strings to prevent "0" prefix issues on mobile
  const [metersInput, setMetersInput] = useState('');
  const [changesInput, setChangesInput] = useState('');

  // Custom Comment Field State
  const [commentInput, setCommentInput] = useState('');
  const [availableComments, setAvailableComments] = useState<string[]>([]);
  const [filteredComments, setFilteredComments] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Management Modal State
  const [showManageModal, setShowManageModal] = useState(false);
  const [editingCommentOldName, setEditingCommentOldName] = useState<string | null>(null);
  const [tempCommentName, setTempCommentName] = useState('');

  const [successMsg, setSuccessMsg] = useState('');

  // Load editing data when record changes
  useEffect(() => {
    if (editingRecord) {
      setFormData({
        date: editingRecord.date,
        shift: editingRecord.shift,
        boss: editingRecord.boss,
        machine: editingRecord.machine,
      });
      setMetersInput(editingRecord.meters.toString());
      setChangesInput(editingRecord.changesCount.toString());
      setCommentInput(editingRecord.changesComment || '');
      // Scroll to top when editing starts
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      // Reset to defaults if not editing
      setFormData({
        date: new Date().toISOString().split('T')[0],
        shift: ShiftType.MORNING,
        boss: BossType.MARTIN,
        machine: MachineType.WH1,
      });
      setMetersInput('');
      setChangesInput('');
      setCommentInput('');
    }
  }, [editingRecord]);

  // Load comments initially and ensure they are up to date
  const refreshComments = () => {
    const comments = getAvailableComments();
    setAvailableComments(comments);
    return comments;
  };

  // Poll for comment updates initially to sync with Firestore
  useEffect(() => {
    refreshComments();
    const interval = setInterval(refreshComments, 2000); // Check for cloud updates to comments
    return () => clearInterval(interval);
  }, []);

  // Filter logic
  useEffect(() => {
    if (!commentInput) {
      setFilteredComments(availableComments);
    } else {
      const lowerInput = commentInput.toLowerCase();
      setFilteredComments(availableComments.filter(c => 
        c.toLowerCase().includes(lowerInput)
      ));
    }
  }, [commentInput, availableComments]);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleMetersChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setMetersInput(rawValue);
  };

  const handleChangesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const rawValue = e.target.value.replace(/\D/g, '');
    setChangesInput(rawValue);
  };

  const formatMeters = (value: string) => {
    if (!value) return '';
    return parseInt(value).toLocaleString('es-ES');
  };

  const clearComment = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent triggering dropdown toggle if overlapping
    setCommentInput('');
    setFilteredComments(availableComments);
    // Keep focus on input ideally, or just clear
  };

  const handleInputFocus = () => {
    refreshComments(); // Sync latest comments from storage on focus
    setShowSuggestions(true);
  };

  const selectComment = (comment: string) => {
    setCommentInput(comment);
    setShowSuggestions(false);
  };

  const handleDeleteComment = async (comment: string) => {
    if (confirm(`¿Borrar "${comment}" de la lista de autocompletado?\n\nNota: Los registros históricos NO se borrarán.`)) {
      await deleteCustomComment(comment);
      refreshComments();
    }
  };

  const startEditingComment = (comment: string) => {
    setEditingCommentOldName(comment);
    setTempCommentName(comment);
  };

  const saveEditedComment = async () => {
    if (!editingCommentOldName || !tempCommentName) return;

    if (tempCommentName !== editingCommentOldName) {
      if (confirm(`¿Renombrar "${editingCommentOldName}" a "${tempCommentName}"?\n\nEsto actualizará TODOS los registros históricos que contengan este comentario para mantener la consistencia.`)) {
        await renameCustomComment(editingCommentOldName, tempCommentName);
        refreshComments();
        // If the current input in the form matches the old name, update it too
        if (commentInput === editingCommentOldName) {
            setCommentInput(tempCommentName);
        }
      }
    }
    setEditingCommentOldName(null);
    setTempCommentName('');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!metersInput) return;

    // Use existing ID if editing, else generate new
    const id = editingRecord ? editingRecord.id : crypto.randomUUID();
    const timestamp = editingRecord ? editingRecord.timestamp : Date.now();

    const newRecord: ProductionRecord = {
      id,
      timestamp,
      date: formData.date,
      shift: formData.shift,
      boss: formData.boss,
      machine: formData.machine,
      meters: parseInt(metersInput),
      changesCount: changesInput === '' ? 0 : parseInt(changesInput),
      changesComment: commentInput
    };

    await saveRecord(newRecord);
    setSuccessMsg(editingRecord ? 'Registro actualizado' : 'Registro guardado');
    onRecordSaved();

    // Refresh available comments in case a new one was added
    refreshComments();

    if (!editingRecord) {
      // Reset production fields only if not editing (if editing, the parent will unmount/reset us)
      setMetersInput('');
      setChangesInput('');
      setCommentInput('');
    }

    setTimeout(() => setSuccessMsg(''), 3000);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-20 md:mb-0">
