  // Check critical blocking condition
  const isConnectionLost = !isOnline || (dbError && dbError.includes('Offline'));

  const NavItem = ({ view, icon: Icon, label, mobileOnly = false }: { view: View; icon: any; label: string, mobileOnly?: boolean }) => (
    <button
