export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { LayoutDashboard, PlusCircle, List, User, Trash2, Lock, AlertCircle, Filter, X, Cloud, WifiOff, CloudOff, Edit, ChevronDown, ChevronUp, Calendar, Monitor, XCircle, FileDown, AlertTriangle } from 'lucide-react';
import ShiftForm from './components/ShiftForm';
import Dashboard from './components/Dashboard';
import { subscribeToRecords, clearAllRecords, deleteRecord, exportToExcel } from './services/storageService';
import { ProductionRecord, FilterState } from './types';
import { MACHINES, BOSSES } from './constants';

type View = 'dashboard' | 'entry' | 'list';
type DeleteMode = 'all' | 'single';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('entry');
  const [records, setRecords] = useState<ProductionRecord[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [dbError, setDbError] = useState('');

  // Edit Mode State
  const [editingRecord, setEditingRecord] = useState<ProductionRecord | null>(null);

  // Filtering State
  const [filters, setFilters] = useState<FilterState>({
    startDate: '',
    endDate: '',
    machine: '',
    boss: ''
  });
  const [showFilters, setShowFilters] = useState(false);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [deleteMode, setDeleteMode] = useState<DeleteMode>('all');
  const [deleteAllStep, setDeleteAllStep] = useState<1 | 2>(1); // 1: Export Warning, 2: Final Confirmation
  const [recordToDelete, setRecordToDelete] = useState<string | null>(null);

  // Real-time synchronization
  useEffect(() => {
    const unsubscribe = subscribeToRecords(
      (updatedRecords) => {
        setRecords(updatedRecords);
        // If we get data, we are connected (unless it's from cache, but we disabled persistence)
        if (dbError && dbError.includes('Offline')) setDbError(''); 
      },
      (errorMsg) => {
        // Now we capture ALL errors, including Offline, to enforce the blocking policy
        setDbError(errorMsg);
      }
    );

    // Monitor connectivity status
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      unsubscribe();
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Filter Logic
  const filteredRecords = useMemo(() => {
    return records.filter(r => {
      const matchDate = (!filters.startDate || r.date >= filters.startDate) && 
                        (!filters.endDate || r.date <= filters.endDate);
      const matchMachine = !filters.machine || r.machine === filters.machine;
      const matchBoss = !filters.boss || r.boss === filters.boss;
      return matchDate && matchMachine && matchBoss;
    });
  }, [records, filters]);

  // Count active filters
  const activeFiltersCount = useMemo(() => {
    let count = 0;
    if (filters.startDate) count++;
    if (filters.endDate) count++;
    if (filters.machine) count++;
    if (filters.boss) count++;
    return count;
  }, [filters]);

  const handleRecordSaved = () => {
    // Exit edit mode if applicable
    setEditingRecord(null);
    // Stay on entry view or allow user to decide
  };

  const handleEdit = (record: ProductionRecord) => {
    setEditingRecord(record);
    setCurrentView('entry');
  };

  const handleCancelEdit = () => {
    setEditingRecord(null);
  };

  const initiateDeleteAll = () => {
    setDeleteMode('all');
    setDeleteAllStep(1); // Reset to step 1
    setRecordToDelete(null);
    setShowDeleteModal(true);
  };

  const initiateDeleteSingle = (id: string) => {
    setDeleteMode('single');
    setRecordToDelete(id);
    setShowDeleteModal(true);
  };

  const handleExportAndContinue = () => {
    exportToExcel(records);
    setDeleteAllStep(2);
  };

  const handleConfirmDelete = () => {
    // Password check removed per requirement
    if (deleteMode === 'all') {
      clearAllRecords();
    } else if (deleteMode === 'single' && recordToDelete) {
      deleteRecord(recordToDelete);
    }
    closeDeleteModal();
  };

