          </div>
        </div>
      </aside>

      {/* --- MAIN CONTENT --- */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen pb-28 md:pb-8">
        <div className="max-w-6xl mx-auto space-y-6">

          {/* Critical Config Error Banner (Not Connection Loss) */}
          {dbError && !dbError.includes('Offline') && (
            <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-r shadow-sm animate-fade-in mb-4">
              <div className="flex items-start">
                <AlertCircle className="w-5 h-5 text-red-500 mt-0.5 mr-3 flex-shrink-0" />
                <div>
                  <h3 className="text-sm font-bold text-red-800">Acción Requerida: Configuración de Base de Datos</h3>
                  <p className="text-sm text-red-700 mt-1">{dbError}</p>
                  {dbError.includes('Base de datos') && (
                    <a 
                      href="https://console.cloud.google.com/datastore/setup?project=registro-jefe-de-turno-2026" 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="text-xs font-bold text-red-600 underline mt-2 block hover:text-red-800"
                    >
                      Haga clic aquí para crear la base de datos en Google Cloud Console &rarr;
                    </a>
