                  </button>
                  <button 
                    onClick={handleConfirmDelete}
                    className="px-4 py-3 rounded-lg bg-red-600 text-white font-bold hover:bg-red-700 shadow-md transition-colors"
                  >
                    Borrar
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}

    </div>
  );
};

