  const startEditingComment = (comment: string) => {
    setEditingCommentOldName(comment);
    setTempCommentName(comment);
  };

  const saveEditedComment = async () => {
    if (!editingCommentOldName || !tempCommentName) return;

    if (tempCommentName !== editingCommentOldName) {
      if (confirm(`¿Renombrar "${editingCommentOldName}" a "${tempCommentName}"?\n\nEsto actualizará TODOS los registros históricos.`)) {
        await renameCustomComment(editingCommentOldName, tempCommentName);
        refreshData();
        if (commentInput === editingCommentOldName) {
            setCommentInput(tempCommentName);
        }
      }
    }
    setEditingCommentOldName(null);
    setTempCommentName('');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!metersInput) return;

    const id = editingRecord ? editingRecord.id : crypto.randomUUID();
    const timestamp = editingRecord ? editingRecord.timestamp : Date.now();

    const newRecord: ProductionRecord = {
      id,
      timestamp,
      date: formData.date,
      shift: formData.shift,
      boss: formData.boss,
      machine: formData.machine,
      meters: parseInt(metersInput),
      changesCount: changesInput === '' ? 0 : parseInt(changesInput),
      changesComment: commentInput,
      operator: operatorInput
    };

    await saveRecord(newRecord);
    setSuccessMsg(editingRecord ? 'Registro actualizado' : 'Registro guardado');
    onRecordSaved();

    refreshData();

    if (!editingRecord) {
      setMetersInput('');
      setChangesInput('');
      setCommentInput('');
      setOperatorInput('');
    }

    setTimeout(() => setSuccessMsg(''), 3000);
