interface DashboardProps {
  records: ProductionRecord[];
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6', '#f43f5e'];

const Dashboard: React.FC<DashboardProps> = ({ records }) => {
  // 1. Calculate Summary Metrics based on FILTERED records
  const summary = useMemo(() => {
    const totalRecords = records.length;

    if (totalRecords === 0) {
      return {
        totalMeters: 0,
        avgMeters: 0,
        totalChanges: 0,
        avgChanges: 0,
        efficiency: 0,
        count: 0
      };
    }

    const totalMeters = records.reduce((acc, r) => acc + r.meters, 0);
    const avgMeters = Math.round(totalMeters / totalRecords);

    const totalChanges = records.reduce((acc, r) => acc + r.changesCount, 0);
    const avgChanges = (totalChanges / totalRecords).toFixed(1);

    // Calculate dynamic efficiency based on filtered set
    // Assuming target 5000m per shift as roughly 100%
    const efficiency = Math.min(100, Math.round((avgMeters / 5000) * 100));

    return {
      totalMeters,
      avgMeters,
      totalChanges,
      avgChanges,
      efficiency,
      count: totalRecords
    };
  }, [records]);

  // 2. Machine Performance Data
  const machineData = useMemo(() => {
    const grouped: Record<string, number> = {};
    records.forEach(r => {
      grouped[r.machine] = (grouped[r.machine] || 0) + r.meters;
    });
    return Object.entries(grouped)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);
  }, [records]);

  // 3. Operator Performance Data
  const operatorData = useMemo(() => {
    const grouped: Record<string, number> = {};
    records.forEach(r => {
      if (r.operator) {
        grouped[r.operator] = (grouped[r.operator] || 0) + r.meters;
      }
    });
    return Object.entries(grouped)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 10); // Top 10
  }, [records]);

  // 4. Shift Distribution
  const shiftData = useMemo(() => {
    const grouped: Record<string, number> = {};
    records.forEach(r => {
      grouped[r.shift] = (grouped[r.shift] || 0) + r.meters;
    });
    return Object.entries(grouped).map(([name, value]) => ({ name, value }));
  }, [records]);

  // 5. Boss Performance
  const bossData = useMemo(() => {
    const grouped: Record<string, number> = {};
    records.forEach(r => {
      grouped[r.boss] = (grouped[r.boss] || 0) + r.meters;
    });
    return Object.entries(grouped).map(([name, value]) => ({ name, value }));
  }, [records]);

  // 6. Incident/Comment Analytics (Normalized)
  const incidentsData = useMemo(() => {
    const groups: Record<string, { count: number, displayName: string }> = {};

    records.forEach(r => {
      if (r.changesComment && r.changesComment.trim().length > 1) {
        const rawComment = r.changesComment.trim();
        const normalizedKey = rawComment
          .normalize("NFD")
          .replace(/[\u0300-\u036f]/g, "")
          .toLowerCase();

        if (!groups[normalizedKey]) {
          groups[normalizedKey] = { count: 0, displayName: rawComment };
        }
        groups[normalizedKey].count += 1;
      }
    });

    return Object.values(groups)
      .map((item) => ({ name: item.displayName, value: item.count }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 5);
  }, [records]);

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Dashboard de Producción</h2>
          <p className="text-sm text-slate-500 flex items-center gap-1">
             <CalendarRange className="w-3 h-3" />
             Mostrando análisis de <span className="font-bold text-slate-700">{summary.count}</span> registros filtrados.
          </p>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <button 
            onClick={() => exportToExcel(records)}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg transition-colors text-sm font-medium shadow-sm"
          >
            <Table className="w-4 h-4" /> Excel
          </button>
          <button 
            onClick={() => exportToPDF(records)}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-lg transition-colors text-sm font-medium shadow-sm"
          >
            <FileText className="w-4 h-4" /> PDF
          </button>
        </div>
      </div>

      {/* KPI Cards - Dynamic based on filters */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-2">
            <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Producción Total</p>
            <Layers className="w-5 h-5 text-blue-500" />
          </div>
          <h3 className="text-3xl font-bold text-slate-900">{summary.totalMeters.toLocaleString()} <span className="text-lg text-slate-400">m</span></h3>
          <p className="text-xs mt-2 font-medium text-slate-500">
             Promedio: <strong>{summary.avgMeters.toLocaleString()} m</strong> / turno
          </p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-2">
            <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Eficiencia Global</p>
            <Activity className="w-5 h-5 text-green-500" />
          </div>
          <h3 className="text-3xl font-bold text-slate-900">{summary.efficiency}%</h3>
          <div className="w-full bg-slate-100 rounded-full h-2 mt-3">
            <div 
              className={`h-2 rounded-full transition-all duration-1000 ${summary.efficiency > 80 ? 'bg-green-500' : summary.efficiency > 50 ? 'bg-orange-500' : 'bg-red-500'}`}
              style={{ width: `${summary.efficiency}%` }}
            ></div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-2">
            <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Media Cambios</p>
            <Activity className="w-5 h-5 text-orange-500" />
          </div>
          <h3 className="text-3xl font-bold text-slate-900">{summary.avgChanges}</h3>
          <p className="text-xs text-slate-400 mt-2 font-medium">Por turno registrado</p>
        </div>
      </div>

      {/* Charts Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Machine Performance */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h4 className="text-sm font-bold text-slate-700 mb-6 uppercase flex items-center gap-2">
            <Activity className="w-4 h-4 text-slate-400" /> Producción por Máquina (Filtrado)
          </h4>
          <div className="h-64 w-full">
             {machineData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={machineData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 10}} interval={0} />
                    <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} tickFormatter={(val) => `${val/1000}k`} />
                    <Tooltip 
                      cursor={{fill: '#f1f5f9'}}
                      contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                    />
                    <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                      {machineData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
             ) : (
                <div className="h-full flex items-center justify-center text-slate-400 text-sm">Sin datos para esta selección</div>
             )}
          </div>
        </div>

        {/* Operator Performance */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h4 className="text-sm font-bold text-slate-700 mb-6 uppercase flex items-center gap-2">
            <Users className="w-4 h-4 text-slate-400" /> Top Operarios (Filtrado)
          </h4>
          {operatorData.length > 0 ? (
            <div className="h-64 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={operatorData} layout="vertical" margin={{ left: 20 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#e2e8f0" />
                  <XAxis type="number" hide />
                  <YAxis 
                    dataKey="name" 
                    type="category" 
                    width={90} 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{fill: '#475569', fontSize: 11, fontWeight: 500}} 
                  />
                  <Tooltip cursor={{fill: '#f1f5f9'}} />
                  <Bar dataKey="value" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={20}>
                    {operatorData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[(index + 4) % COLORS.length]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
             <div className="h-64 flex flex-col items-center justify-center text-slate-400 gap-2 border-2 border-dashed border-slate-100 rounded-lg">
              <Users className="w-8 h-8 opacity-50" />
              <p className="text-sm">Sin datos de operarios</p>
            </div>
          )}
        </div>

        {/* Boss & Shift Distribution */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
           <h4 className="text-sm font-bold text-slate-700 mb-6 uppercase">Distribución de Carga (Filtrado)</h4>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8 h-64">

              {/* Shift Pie Chart */}
              <div className="w-full h-full relative">
                 <h5 className="absolute top-0 left-0 text-xs font-bold text-slate-400">POR TURNO</h5>
                 {shiftData.length > 0 ? (
                   <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={shiftData}
                          cx="50%"
                          cy="50%"
                          innerRadius={60}
                          outerRadius={80}
                          paddingAngle={5}
                          dataKey="value"
                        >
                          {shiftData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip />
                        <Legend verticalAlign="bottom" height={36} />
                      </PieChart>
                   </ResponsiveContainer>
                 ) : <div className="h-full flex items-center justify-center text-slate-300">Sin datos</div>}
              </div>

              {/* Boss Pie Chart */}
              <div className="w-full h-full relative">
                 <h5 className="absolute top-0 left-0 text-xs font-bold text-slate-400">POR JEFE</h5>
                 {bossData.length > 0 ? (
                   <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={bossData}
                          cx="50%"
                          cy="50%"
                          innerRadius={60}
                          outerRadius={80}
                          paddingAngle={5}
                          dataKey="value"
                        >
                          {bossData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[(index + 3) % COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip />
                        <Legend verticalAlign="bottom" height={36} />
                      </PieChart>
                   </ResponsiveContainer>
                 ) : <div className="h-full flex items-center justify-center text-slate-300">Sin datos</div>}
              </div>
           </div>
        </div>

        {/* Incidents Analytics */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
          <div className="flex justify-between items-center mb-6">
             <h4 className="text-sm font-bold text-slate-700 uppercase">Motivos de Cambios Recurrentes</h4>
             {incidentsData.length > 0 && <span className="text-xs text-orange-600 bg-orange-50 px-2 py-1 rounded-full font-bold">Patrones detectados</span>}
          </div>

          {incidentsData.length > 0 ? (
            <div className="h-64 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={incidentsData} layout="vertical" margin={{ left: 20 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#e2e8f0" />
                  <XAxis type="number" hide />
                  <YAxis 
                    dataKey="name" 
                    type="category" 
                    width={150} 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{fill: '#475569', fontSize: 11, fontWeight: 500}} 
                  />
                  <Tooltip cursor={{fill: '#f1f5f9'}} />
                  <Bar dataKey="value" fill="#ef4444" radius={[0, 4, 4, 0]} barSize={20} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="h-64 flex flex-col items-center justify-center text-slate-400 gap-2 border-2 border-dashed border-slate-100 rounded-lg">
              <AlertTriangle className="w-8 h-8 opacity-50" />
              <p className="text-sm">Sin suficientes datos de incidencias</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

