                          <td className="px-6 py-4 text-center text-slate-600 hidden sm:table-cell">
                            {r.changesCount}
                          </td>
                          <td className="px-6 py-4 text-slate-500 max-w-xs truncate hidden sm:table-cell" title={r.changesComment}>
